# Generated by Codex for Pyomo DoE PDE diffusion diagnostic execution
"""
Helper utility executed inside a conda environment to run controlled PDE
diffusion diagnostics without modifying the model source files.
"""

from __future__ import annotations

import argparse
import json
import os
import re
import time
from pathlib import Path
from typing import Dict, Tuple


def parse_args() -> argparse.Namespace:
    """
    Parse CLI arguments for diagnostic execution.

    Returns:
        Parsed arguments namespace.
    """
    parser = argparse.ArgumentParser()
    parser.add_argument("--method", choices=["central", "symbolic"], required=True)
    parser.add_argument("--mode", choices=["baseline", "no_solve", "solve_twice"], required=True)
    parser.add_argument("--nfe_x", type=int, required=True)
    parser.add_argument("--nfe_t", type=int, required=True)
    parser.add_argument("--out_json", type=str, required=True)
    parser.add_argument("--run_dir", type=str, required=True)
    parser.add_argument("--ipopt_out", type=str, default="")
    parser.add_argument("--ipopt_exe", type=str, default="")
    return parser.parse_args()


def load_module(method: str):
    """
    Load the PDE diffusion module for the specified method.

    Parameters:
        method: "central" or "symbolic".

    Returns:
        Imported module object.
    """
    if method == "central":
        import PDE_diffusion_central as mod
    else:
        import PDE_diffusion_sym as mod
    return mod


def parse_ipopt_extras(ipopt_out_path: str) -> Dict[str, object]:
    """
    Parse additional IPOPT metrics not included in model helper parsers.

    Parameters:
        ipopt_out_path: IPOPT output file path.

    Returns:
        Dictionary with extra IPOPT/model-size metrics.
    """
    if not ipopt_out_path or not Path(ipopt_out_path).exists():
        return {}

    txt = Path(ipopt_out_path).read_text(encoding="utf-8", errors="replace")

    def grab_int(pat: str):
        match = re.search(pat, txt)
        return int(match.group(1)) if match else None

    def grab_float(pat: str):
        match = re.search(pat, txt)
        return float(match.group(1)) if match else None

    # NOTE: This IPOPT build may not emit an aggregate MA57 linear-solver time.
    # Keep multiple patterns and default to None if absent.
    ma57_time = (
        grab_float(r"Total CPU secs in linear solver\s*=\s*([0-9.+-eE]+)")
        or grab_float(r"Total seconds in linear solver\s*=\s*([0-9.+-eE]+)")
        or grab_float(r"Linear solver time\s*=\s*([0-9.+-eE]+)")
    )

    return {
        "n_variables": grab_int(r"Total number of variables\.*:\s*(\d+)"),
        "n_constraints": grab_int(
            r"Total number of equality constraints\.*:\s*(\d+)"
        ),
        "ma57_linear_solver_time": ma57_time,
    }


def parse_ipopt_basic_fast(ipopt_out_path: str) -> Dict[str, object]:
    """
    Parse core IPOPT counters quickly via line scans to avoid expensive
    whole-file regex on very large logs.
    """
    path = Path(ipopt_out_path)
    if not ipopt_out_path or not path.exists():
        return {}

    patterns = {
        "iterations": re.compile(r"Number of Iterations.*:\s+(\d+)"),
        "obj_eval_count": re.compile(
            r"Number of objective function evaluations\s*=\s*(\d+)"
        ),
        "grad_eval_count": re.compile(
            r"Number of objective gradient evaluations\s*=\s*(\d+)"
        ),
        "eq_con_eval_count": re.compile(
            r"Number of equality constraint evaluations\s*=\s*(\d+)"
        ),
        "eq_con_jac_eval_count": re.compile(
            r"Number of equality constraint Jacobian evaluations\s*=\s*(\d+)"
        ),
        "hess_eval_count": re.compile(
            r"Number of Lagrangian Hessian evaluations\s*=\s*(\d+)"
        ),
        "ipopt_cpu_secs_no_eval": re.compile(
            r"Total CPU secs in IPOPT \(w/o function evaluations\)\s*=\s*([0-9.]+)"
        ),
        "nlp_cpu_secs_eval": re.compile(
            r"Total CPU secs in NLP function evaluations\s*=\s*([0-9.]+)"
        ),
        "exit": re.compile(r"EXIT:\s*(.*)"),
    }

    out: Dict[str, object] = {}
    with path.open("r", encoding="utf-8", errors="replace") as handle:
        for line in handle:
            for key, pat in patterns.items():
                if key in out:
                    continue
                match = pat.search(line)
                if not match:
                    continue
                if key.endswith("_count") or key == "iterations" or key == "hess_eval_count":
                    out[key] = int(match.group(1))
                elif key in ("ipopt_cpu_secs_no_eval", "nlp_cpu_secs_eval"):
                    out[key] = float(match.group(1))
                else:
                    out[key] = match.group(1).strip()
            if len(out) == len(patterns):
                break
    return out


def _count_explicit_zeros(values) -> int:
    count = 0
    for value in values:
        if isinstance(value, bool):
            continue
        if isinstance(value, (int, float)) and value == 0:
            count += 1
    return count


def enable_symbolic_instrumentation() -> Dict[str, object]:
    """
    Monkeypatch ExperimentGradients methods to capture symbolic differentiation
    timing and derivative-entry density metrics.

    Returns:
        Instrumentation state dictionary with a callable at key "restore".
    """
    from pyomo.contrib.doe.utils import ExperimentGradients

    state: Dict[str, object] = {
        "perform_differentiation_time": 0.0,
        "perform_differentiation_calls": 0,
        "compute_gradient_time": 0.0,
        "compute_gradient_calls": 0,
        "total_derivative_entries_stored": None,
        "number_of_nonzero_derivatives": None,
        "number_of_explicit_zero_entries": None,
        "experiment_num_constraints": None,
        "experiment_num_variables": None,
    }

    original_perform = ExperimentGradients._perform_differentiation
    original_compute = ExperimentGradients.compute_gradient_outputs_wrt_unknown_parameters

    def wrapped_perform(self, symbolic=True, automatic=True):
        start = time.perf_counter()
        result = original_perform(self, symbolic=symbolic, automatic=automatic)
        state["perform_differentiation_time"] += time.perf_counter() - start
        state["perform_differentiation_calls"] += 1

        if symbolic and getattr(self, "jac_dict_sd", None) is not None:
            jac = self.jac_dict_sd
            total_entries = len(jac)
            explicit_zeros = _count_explicit_zeros(jac.values())
            state["total_derivative_entries_stored"] = total_entries
            state["number_of_explicit_zero_entries"] = explicit_zeros
            state["number_of_nonzero_derivatives"] = total_entries - explicit_zeros
            state["experiment_num_constraints"] = getattr(self, "num_constraints", None)
            state["experiment_num_variables"] = getattr(self, "num_vars", None)
        return result

    def wrapped_compute(self):
        start = time.perf_counter()
        result = original_compute(self)
        state["compute_gradient_time"] += time.perf_counter() - start
        state["compute_gradient_calls"] += 1
        return result

    ExperimentGradients._perform_differentiation = wrapped_perform
    ExperimentGradients.compute_gradient_outputs_wrt_unknown_parameters = wrapped_compute

    def restore():
        ExperimentGradients._perform_differentiation = original_perform
        ExperimentGradients.compute_gradient_outputs_wrt_unknown_parameters = original_compute

    state["restore"] = restore
    return state


def create_doe(
    mod,
    nfe_x: int,
    nfe_t: int,
    ipopt_out: str,
    method: str,
    ipopt_exe: str,
):
    """
    Construct the DesignOfExperiments object using module defaults.

    Parameters:
        mod: Imported module.
        nfe_x: Spatial discretization.
        nfe_t: Temporal discretization.
        ipopt_out: IPOPT output file path.

    Returns:
        Tuple of (doe_obj, experiment).
    """
    ncp_x = getattr(mod, "ncp_x", 2)
    ncp_t = getattr(mod, "ncp_t", 2)
    experiment = mod.PDE_diffusion(
        data=mod.data_ex,
        nfe_t=nfe_t,
        nfe_x=nfe_x,
        ncp_x=ncp_x,
        ncp_t=ncp_t,
    )
    if ipopt_exe:
        mod.IPOPT_BIN = ipopt_exe
    solver = mod.make_ipopt(ipopt_out)

    doe_kwargs = {
        "fd_formula": mod.fd_formula,
        "step": mod.step_size,
        "objective_option": mod.objective_option,
        "scale_constant_value": 1,
        "scale_nominal_param_value": mod.scale_nominal_param_value,
        "prior_FIM": None,
        "jac_initial": None,
        "fim_initial": None,
        "L_diagonal_lower_bound": 1e-7,
        "solver": solver,
        "tee": True,
        "get_labeled_model_args": None,
        "_Cholesky_option": True,
        "_only_compute_fim_lower": True,
    }
    if method == "symbolic":
        doe_kwargs["gradient_method"] = "pynumero"

    doe_obj = mod.DesignOfExperiments(experiment, **doe_kwargs)
    return doe_obj, experiment


def build_and_initialize(doe_obj) -> Tuple[float, float, object]:
    """
    Build and initialize the DoE model without solving the full optimization.

    Parameters:
        doe_obj: DesignOfExperiments instance.

    Returns:
        Tuple of (build_time, init_time, model).
    """
    from pyomo.common.timing import TicTocTimer
    import pyomo.environ as pyo

    timer = TicTocTimer()
    timer.tic(msg=None)

    model = doe_obj.model
    if not doe_obj._built_scenarios:
        doe_obj.create_doe_model(model=model)
    if getattr(doe_obj, "use_grey_box", False):
        doe_obj.create_grey_box_objective_function(model=model)
    else:
        doe_obj.create_objective_function(model=model)

    build_time = timer.toc(msg=None)

    model.objective.deactivate()
    model.obj_cons.deactivate()
    for comp in model.scenario_blocks[0].experiment_inputs:
        comp.fix()

    model.dummy_obj = pyo.Objective(expr=0, sense=pyo.minimize)
    doe_obj.solver.solve(model, tee=doe_obj.tee)

    init_time = timer.toc(msg=None)

    model.dummy_obj.deactivate()
    for comp in model.scenario_blocks[0].experiment_inputs:
        comp.unfix()
    model.objective.activate()
    model.obj_cons.activate()

    return build_time, init_time, model


def run_baseline(mod, args: argparse.Namespace) -> Dict[str, object]:
    """
    Run a baseline build+init+solve diagnostic.

    Parameters:
        mod: Imported module.
        args: Parsed CLI arguments.

    Returns:
        Result dictionary for JSON output.
    """
    run_dir = Path(args.run_dir)
    run_dir.mkdir(parents=True, exist_ok=True)
    ipopt_out = args.ipopt_out or str(run_dir / "ipopt.out")

    instrumentation = None
    if args.method == "symbolic":
        instrumentation = enable_symbolic_instrumentation()

    try:
        doe_obj, _ = create_doe(
            mod,
            args.nfe_x,
            args.nfe_t,
            ipopt_out,
            args.method,
            args.ipopt_exe,
        )
        build_time, init_time, model = build_and_initialize(doe_obj)
    finally:
        if instrumentation is not None:
            instrumentation["restore"]()

    solve_start = time.time()
    doe_obj.solver.solve(model, tee=doe_obj.tee)
    solve_time = time.time() - solve_start

    ipopt_stats = parse_ipopt_basic_fast(ipopt_out)
    ipopt_extra = parse_ipopt_extras(ipopt_out)
    n_constraints = ipopt_extra.get("n_constraints")
    n_variables = ipopt_extra.get("n_variables")
    total_entries = None
    nonzeros = None
    explicit_zeros = None
    differentiation_time = None
    if instrumentation is not None:
        total_entries = instrumentation.get("total_derivative_entries_stored")
        nonzeros = instrumentation.get("number_of_nonzero_derivatives")
        explicit_zeros = instrumentation.get("number_of_explicit_zero_entries")
        differentiation_time = (
            instrumentation.get("perform_differentiation_time", 0.0)
            + instrumentation.get("compute_gradient_time", 0.0)
        )

    result = {
        "method": args.method,
        "nfe_x": args.nfe_x,
        "nfe_t": args.nfe_t,
        "total_build_time": build_time,
        "differentiation_time": differentiation_time,
        "doe_build_time": build_time,
        "doe_init_time": init_time,
        "doe_solve_time": solve_time,
        "doe_wall_time": build_time + init_time + solve_time,
        "n_constraints": n_constraints,
        "n_variables": n_variables,
        "problem_size_metric": (
            (n_constraints * n_variables)
            if n_constraints is not None and n_variables is not None
            else None
        ),
        "total_derivative_entries_stored": total_entries,
        "number_of_nonzero_derivatives": nonzeros,
        "number_of_explicit_zero_entries": explicit_zeros,
        "derivative_density": (
            (nonzeros / total_entries)
            if total_entries not in (None, 0) and nonzeros is not None
            else None
        ),
        "ipopt_iters": ipopt_stats.get("iterations"),
        "obj_eval": ipopt_stats.get("obj_eval_count"),
        "grad_eval": ipopt_stats.get("grad_eval_count"),
        "eq_con_eval": ipopt_stats.get("eq_con_eval_count"),
        "eq_jac_eval": ipopt_stats.get("eq_con_jac_eval_count"),
        "hess_eval": ipopt_stats.get("hess_eval_count"),
        "ma57_linear_solver_time": ipopt_extra.get("ma57_linear_solver_time"),
        "ipopt_cpu_wo_feval": ipopt_stats.get("ipopt_cpu_secs_no_eval"),
        "ipopt_cpu_nlp_feval": ipopt_stats.get("nlp_cpu_secs_eval"),
        "ipopt_exit": ipopt_stats.get("exit"),
        "ipopt_exe": args.ipopt_exe or getattr(mod, "IPOPT_BIN", None),
        "ipopt_linear_solver": (
            os.environ.get("IPOPT_LINEAR_SOLVER")
            or getattr(mod, "IPOPT_LINEAR_SOLVER_DEFAULT", None)
        ),
    }
    return result


