def run_solve_twice(mod, args: argparse.Namespace) -> Dict[str, object]:
    """
    Run a diagnostic that solves twice after build+init.

    Parameters:
        mod: Imported module.
        args: Parsed CLI arguments.

    Returns:
        Result dictionary for JSON output.
    """
    run_dir = Path(args.run_dir)
    run_dir.mkdir(parents=True, exist_ok=True)
    ipopt_out_1 = args.ipopt_out or str(run_dir / "ipopt_solve1.out")
    ipopt_out_2 = str(run_dir / "ipopt_solve2.out")

    doe_obj, _ = create_doe(
        mod,
        args.nfe_x,
        args.nfe_t,
        ipopt_out_1,
        args.method,
        args.ipopt_exe,
    )
    build_time, init_time, model = build_and_initialize(doe_obj)

    solve1_start = time.time()
    doe_obj.solver.solve(model, tee=doe_obj.tee)
    solve1_time = time.time() - solve1_start
    ipopt_stats_1 = mod.parse_ipopt_out(ipopt_out_1)

    solver2 = mod.make_ipopt(ipopt_out_2)
    solve2_start = time.time()
    solver2.solve(model, tee=doe_obj.tee)
    solve2_time = time.time() - solve2_start
    ipopt_stats_2 = mod.parse_ipopt_out(ipopt_out_2)

    result = {
        "method": args.method,
        "nfe_x": args.nfe_x,
        "nfe_t": args.nfe_t,
        "doe_build_time": build_time,
        "doe_init_time": init_time,
        "doe_wall_time": build_time + init_time + solve1_time + solve2_time,
        "solve1_time": solve1_time,
        "solve2_time": solve2_time,
        "solve1_ipopt_iters": ipopt_stats_1.get("iterations"),
        "solve2_ipopt_iters": ipopt_stats_2.get("iterations"),
        "solve1_obj_eval": ipopt_stats_1.get("obj_eval_count"),
        "solve2_obj_eval": ipopt_stats_2.get("obj_eval_count"),
        "solve1_grad_eval": ipopt_stats_1.get("grad_eval_count"),
        "solve2_grad_eval": ipopt_stats_2.get("grad_eval_count"),
        "solve1_eq_con_eval": ipopt_stats_1.get("eq_con_eval_count"),
        "solve2_eq_con_eval": ipopt_stats_2.get("eq_con_eval_count"),
        "solve1_eq_jac_eval": ipopt_stats_1.get("eq_con_jac_eval_count"),
        "solve2_eq_jac_eval": ipopt_stats_2.get("eq_con_jac_eval_count"),
        "solve1_hess_eval": ipopt_stats_1.get("hess_eval_count"),
        "solve2_hess_eval": ipopt_stats_2.get("hess_eval_count"),
        "solve1_cpu_wo_feval": ipopt_stats_1.get("ipopt_cpu_secs_no_eval"),
        "solve2_cpu_wo_feval": ipopt_stats_2.get("ipopt_cpu_secs_no_eval"),
        "solve1_cpu_nlp_feval": ipopt_stats_1.get("nlp_cpu_secs_eval"),
        "solve2_cpu_nlp_feval": ipopt_stats_2.get("nlp_cpu_secs_eval"),
        "solve1_ipopt_exit": ipopt_stats_1.get("exit"),
        "solve2_ipopt_exit": ipopt_stats_2.get("exit"),
        "ipopt_exe": args.ipopt_exe or getattr(mod, "IPOPT_BIN", None),
        "ipopt_linear_solver": (
            os.environ.get("IPOPT_LINEAR_SOLVER")
            or getattr(mod, "IPOPT_LINEAR_SOLVER_DEFAULT", None)
        ),
    }
    return result


def main() -> None:
    """
    Entry point for running the helper diagnostic mode.
    """
    args = parse_args()
    mod = load_module(args.method)

    if args.mode == "baseline":
        result = run_baseline(mod, args)
    elif args.mode == "no_solve":
        result = run_no_solve(mod, args)
    else:
        result = run_solve_twice(mod, args)

    out_path = Path(args.out_json)
    out_path.parent.mkdir(parents=True, exist_ok=True)
    with out_path.open("w", encoding="utf-8") as handle:
        json.dump(result, handle, indent=2)


if __name__ == "__main__":
    main()
